import psutil
import ray
import mlflow
from prometheus_client import CollectorRegistry, push_to_gateway
from datetime import datetime

def check_gpu_utilization():
    """Differentiates training vs inference GPU usage via process analysis"""
    gpus = psutil.cuda.device_count()
    utilization_data = {}

    for i in range(gpus):
        handle = psutil.cuda.device(i)
        utilization_data[i] = {
            'total_util': handle.utilization(),
            'processes': []
        }

        for proc in psutil.process_iter(['pid', 'name', 'cmdline']):
            try:
                if proc.info['cmdline'] and any('tensorflow' in p.lower() or 
                                               'pytorch' in p.lower() or 
                                               'torch' in p.lower() for p in proc.info['cmdline']):
                    utilization_data[i]['processes'].append({
                        'pid': proc.info['pid'],
                        'name': proc.info['name'],
                        'gpu_mem': proc.memory_info().rss / 1024**2,
                        'is_training': 'train' in proc.info['name'].lower() or 
                                      any('train' in arg.lower() for arg in proc.info['cmdline'])
                    })
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                continue

    return utilization_data

def check_mlflow_status():
    """Verifies MLflow tracking server health and active experiments"""
    try:
        client = mlflow.tracking.MlflowClient()
        active_experiments = client.get_experiments()
        running_runs = 0

        for exp in active_experiments:
            if exp.lifecycle_stage == "RUNNING":
                running_runs += 1

        return {
            'status': 'healthy' if client.get_tracking_uri() else 'error',
            'active_experiments': len(active_experiments),
            'running_runs': running_runs,
            'message': f"MLflow: {running_runs}/{len(active_experiments)} active runs"
        }
    except Exception as e:
        return {'status': 'error', 'message': f"MLflow check failed: {str(e)}"}

def check_ray_status():
    """Assesses Ray cluster health and node status"""
    try:
        cluster_status = ray.cluster_status()
        return {
            'status': 'healthy',
            'nodes': len(cluster_status.nodes),
            'available_nodes': len(cluster_status.nodes_available),
            'message': f"Ray: {cluster_status.nodes_available}/{cluster_status.nodes} nodes available"
        }
    except Exception as e:
        return {'status': 'error', 'message': f"Ray check failed: {str(e)}"}

def check_prometheus_gateway():
    """Validates Prometheus pushgateway connectivity"""
    try:
        registry = CollectorRegistry()
        # Test metric creation
        Counter('test_metric', 'Test metric').collect(registry)
        # Attempt push
        push_to_gateway('localhost:9091', job='health_check', registry=registry)
        return {'status': 'healthy', 'message': 'Prometheus gateway reachable'}
    except Exception as e:
        return {'status': 'error', 'message': f"Prometheus check failed: {str(e)}"}

def get_training_telemetry():
    """Collects active training metrics when training processes detected"""
    telemetry = {}
    utilization = check_gpu_utilization()

    for gpu_id, data in utilization.items():
        for proc in data['processes']:
            if proc.get('is_training'):
                telemetry.setdefault('training_sessions', []).append({
                    'gpu_id': gpu_id,
                    'pid': proc['pid'],
                    'memory_mb': round(proc['gpu_mem'], 1),
                    'process_name': proc['name'],
                    'timestamp': datetime.now().isoformat()
                })
    return telemetry

def generate_report():
    """Comprehensive health report with error handling"""
    report = {
        'timestamp': datetime.now().isoformat(),
        'sections': {}
    }

    # GPU Analysis
    gpu_data = check_gpu_utilization()
    report['sections']['gpu_utilization'] = {
        'total_gpus': psutil.cuda.device_count(),
        'utilization': gpu_data,
        'warning': 'High inference usage detected - verify expected training loads' 
                  if any(d['total_util'] > 80 for d in gpu_data.values()) 
                  and not any(p['is_training'] for d in gpu_data.values() for p in d['processes'])
                  else ''
    }

    # MLflow Check
    mlflow_result = check_mlflow_status()
    report['sections']['mlflow'] = mlflow_result

    # Ray Check
    ray_result = check_ray_status()
    report['sections']['ray'] = ray_result

    # Prometheus Check
    prom_result = check_prometheus_gateway()
    report['sections']['prometheus'] = prom_result

    # Training Telemetry
    telemetry = get_training_telemetry()
    report['sections']['training_telemetry'] = telemetry

    # Error handling guidance
    if any(s['status'] == 'error' for s in [mlflow_result, ray_result, prom_result]):
        report['sections']['error_handling'] = {
            'action': 'Investigate failed component using individual health checks',
            'commands': {
                'mlflow': 'mlflow ui --port 5000',
                'ray': 'ray status',
                'prometheus': 'curl http://localhost:9091/metrics'
            }
        }
    else:
        report['sections']['error_handling'] = {'status': 'all_systems_healthy'}

    return report

# Activation triggers
if __name__ == "__main__":
    import sys
    triggers = {
        'mlflow status': check_mlflow_status,
        'ray status': check_ray_status,
        'training progress': lambda: get_training_telemetry() if get_training_telemetry() else {},
        'pushgateway': check_prometheus_gateway
    }

    trigger = sys.argv[1] if len(sys.argv) > 1 else None
    if trigger in triggers:
        result = triggers[trigger]()
        print(f"=== {trigger.upper()} REPORT ===")
        print(result)
    else:
        print("Unknown trigger. Valid triggers:", list(triggers.keys()))
